function ConfirmDelete() {
  const [open, setOpen] = useState(false);
  const triggerRef = useRef(null);
  const cancelRef = useRef(null);

  useEffect(() => {
    if (open) cancelRef.current?.focus();
    else triggerRef.current?.focus();
  }, [open]);

  useEffect(() => {
    if (!open) return;
    const onKey = (e) => { if (e.key === 'Escape') setOpen(false); };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [open]);

  return (
    <div>
      <button ref={triggerRef} onClick={() => setOpen(true)}>파일 삭제</button>

      {open && (
        <div className="overlay" onClick={() => setOpen(false)}>
          <div
            role="alertdialog"
            aria-modal="true"
            aria-labelledby="confirm-title"
            aria-describedby="confirm-desc"
            className="dialog"
            onClick={(e) => e.stopPropagation()}
          >
            <h2 id="confirm-title">파일을 삭제하시겠습니까?</h2>
            <p id="confirm-desc">report.pdf 파일이 영구적으로 삭제되며 복구할 수 없습니다.</p>
            <div className="dialog-actions">
              <button ref={cancelRef} onClick={() => setOpen(false)}>취소</button>
              <button className="danger" onClick={() => setOpen(false)}>삭제</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
